     1→import { useEffect, useRef, useState } from 'react';
     2→import type { Bot, ChatMessage, Conversation, Provider } from '../types';
     3→import type { StreamingContent, StreamPart } from '../App';
     4→
     5→type DisplayMessage = ChatMessage | { role: 'assistant'; parts: StreamPart[] };
     6→
     7→interface ChatWindowProps {
     8→  headerTitle: string;
     9→  conversation: Conversation | null;
    10→  providers: Provider[];
    11→  bots: Bot[];
    12→  sending: boolean;
    13→  streaming: StreamingContent | null;
    14→  lastStreamedContent: { reasoning: string; parts: StreamPart[] } | null;
    15→  inputDraft: string;
    16→  onInputDraftChange: (value: string) => void;
    17→  onSend: (message: string) => void;
    18→  onUpdateProvider: (conversationId: string, providerId: string | null) => void;
    19→  onUpdateBot: (conversationId: string, botName: string | null) => void;
    20→}
    21→
    22→const PREVIEW_LENGTH = 120;
    23→
    24→function formatTime(ms: number): string {
    25→  const d = new Date(ms);
    26→  const pad = (n: number) => n.toString().padStart(2, '0');
    27→  const pad3 = (n: number) => n.toString().padStart(3, '0');
    28→  return `${pad(d.getHours())}:${pad(d.getMinutes())}:${pad(d.getSeconds())}.${pad3(d.getMilliseconds())}`;
    29→}
    30→
    31→function roleDisplayName(role: string, conversation: Conversation | null): string {
    32→  if (!conversation) return role;
    33→  if (role === 'user') {
    34→    const p1 = conversation.participant1 ?? '';
    35→    const p2 = conversation.participant2 ?? '';
    36→    const bot = conversation.botName ?? '';
    37→    if (p1 && p2 && bot && p1 !== 'user' && p2 !== 'user') {
    38→      return p1 === bot ? p2 : p1;
    39→    }
    40→    return 'user';
    41→  }
    42→  if (role === 'assistant') {
    43→    const bot = conversation.botName ?? '';
    44→    if (bot) return bot;
    45→    const p1 = conversation.participant1 ?? '';
    46→    const p2 = conversation.participant2 ?? '';
    47→    if (p1 && p2) return p1 === 'user' ? p2 : p2 === 'user' ? p1 : p2;
    48→  }
    49→  return role;
    50→}
    51→
    52→function MessageEntry({ msg, conversation }: { msg: DisplayMessage; conversation: Conversation | null }) {
    53→  const hasParts = 'parts' in msg && msg.parts != null;
    54→  const [collapsed, setCollapsed] = useState(msg.role === 'tool' && !hasParts);
    55→  const content = 'content' in msg ? msg.content : '';
    56→  const preview = content.slice(0, PREVIEW_LENGTH) + (content.length > PREVIEW_LENGTH ? '…' : '');
    57→  const timeStr = 'timestampMillis' in msg && msg.timestampMillis != null && msg.timestampMillis > 0
    58→    ? formatTime(msg.timestampMillis) : null;
    59→  const displayName = roleDisplayName(msg.role, conversation);
    60→
    61→  const messageStyles =
    62→    msg.role === 'user'
    63→      ? 'max-w-[80%] py-2.5 px-3.5 rounded-lg text-sm leading-relaxed whitespace-pre-wrap break-words self-end bg-user-bg text-text-bright'
    64→      : msg.role === 'tool'
    65→        ? 'max-w-[90%] py-2.5 px-3.5 rounded-lg text-xs leading-relaxed whitespace-pre-wrap break-words self-start bg-tool-bg border border-tool-border font-mono'
    66→        : 'max-w-[80%] py-2.5 px-3.5 rounded-lg text-sm leading-relaxed whitespace-pre-wrap break-words self-start bg-assistant-bg border border-border';
    67→
    68→  return (
    69→    <div className={`${messageStyles}${collapsed ? ' pb-0' : ''}`}>
    70→      <div
    71→        className="flex items-baseline gap-2 cursor-pointer select-none"
    72→        onClick={() => setCollapsed((v) => !v)}
    73→      >
    74→        <span className={`text-[0.6875rem] font-semibold tracking-wide text-text-dim shrink-0 ${['user', 'assistant', 'tool'].includes(displayName.toLowerCase()) ? 'uppercase' : ''}`}>
    75→          {displayName}
    76→        </span>
    77→        {timeStr != null && (
    78→          <span className="text-[0.6875rem] tabular-nums text-text-dim opacity-85">{timeStr}</span>
    79→        )}
    80→        {collapsed && (
    81→          <span className="flex-1 text-[0.8125rem] text-text-dim whitespace-nowrap overflow-hidden text-ellipsis">
    82→            {preview}
    83→          </span>
    84→        )}
    85→        <button
    86→          className="flex items-center justify-center w-6 h-6 shrink-0 ml-auto rounded-md border border-border bg-bg-input/60 text-text-dim text-[0.65rem] font-medium cursor-pointer transition-all duration-150 hover:border-accent hover:text-accent hover:bg-bg-hover"
    87→          title={collapsed ? 'Expand' : 'Collapse'}
    88→        >
    89→          {collapsed ? '▸' : '▾'}
    90→        </button>
    91→      </div>
    92→      {!collapsed && (
    93→        <div className="text-text-bright mt-1.5 min-w-0 break-words">
    94→          {hasParts
    95→            ? (msg as { role: 'assistant'; parts: StreamPart[] }).parts.map((part, i) =>
    96→                part.type === 'tool' ? (
    97→                  <details key={i} className="message-tool-part my-2 py-2 px-2.5 bg-tool-bg border border-tool-border rounded-lg text-tool-text max-w-full overflow-hidden" open>
    98→                    <summary className="flex items-center gap-2 cursor-pointer text-xs font-semibold uppercase text-tool-summary list-none [&::-webkit-details-marker]:hidden [&::marker]:hidden">
    99→                      <span>Tool</span>
   100→                      <span className="btn-msg-toggle flex items-center justify-center w-6 h-6 ml-auto shrink-0 rounded-md border border-tool-border bg-tool-bg/80 text-[0.65rem] font-medium leading-none transition-all duration-150 hover:border-tool-summary hover:opacity-90" />
   101→                    </summary>
   102→                    <pre className="mt-1.5 font-mono text-xs text-tool-text whitespace-pre-wrap break-words max-w-full overflow-x-auto overflow-y-hidden">
   103→                      {part.content}
   104→                    </pre>
   105→                  </details>
   106→                ) : part.type === 'reasoning' ? (
   107→                  <details key={i} className="mb-2" open>
   108→                    <summary className="cursor-pointer text-text-dim text-xs font-semibold uppercase">
   109→                      Thinking
   110→                    </summary>
   111→                    <pre className="mt-1.5 p-2 bg-bg rounded-lg text-xs text-text-dim whitespace-pre-wrap break-words max-h-[200px] overflow-y-auto">
   112→                      {part.content}
   113→                    </pre>
   114→                  </details>
   115→                ) : (
   116→                  <span key={i}>{part.content}</span>
   117→                )
   118→              )
   119→            : content}
   120→        </div>
   121→      )}
   122→    </div>
   123→  );
   124→}
   125→
   126→function parseStructuredContent(content: string): StreamPart[] | null {
   127→  if (!content || typeof content !== 'string') return null;
   128→  const trimmed = content.trim();
   129→  if (!trimmed.startsWith('{"parts":')) return null;
   130→  try {
   131→    const data = JSON.parse(content) as { parts?: Array<{ type: string; content: string }> };
   132→    if (!Array.isArray(data.parts)) return null;
   133→    const parts: StreamPart[] = data.parts
   134→      .filter((p) => p && (p.type === 'answer' || p.type === 'tool' || p.type === 'reasoning') && typeof p.content === 'string')
   135→      .map((p) => ({ type: p.type as 'answer' | 'tool' | 'reasoning', content: p.content }));
   136→    return parts.length > 0 ? parts : null;
   137→  } catch {
   138→    return null;
   139→  }
   140→}
   141→
   142→function filterParts(parts: StreamPart[], hideToolsAndThinking: boolean): StreamPart[] {
   143→  if (!hideToolsAndThinking) return parts;
   144→  const answerParts = parts.filter((p) => p.type === 'answer');
   145→  return answerParts.map((p, i, arr) => ({
   146→    ...p,
   147→    content: p.content + (i < arr.length - 1 ? '\n\n' : ''),
   148→  }));
   149→}
   150→
   151→function getDisplayMessages(
   152→  messages: ChatMessage[],
   153→  hideToolsAndThinking: boolean,
   154→  lastStreamedContent: { reasoning: string; parts: StreamPart[] } | null
   155→): DisplayMessage[] {
   156→  let list: DisplayMessage[] = messages.map((msg) => {
   157→    if (msg.role === 'assistant') {
   158→      const parts = parseStructuredContent(msg.content);
   159→      if (parts) return { role: 'assistant' as const, parts: filterParts(parts, hideToolsAndThinking) };
   160→    }
   161→    return msg;
   162→  });
   163→  if (lastStreamedContent && list.length > 0) {
   164→    const lastUserIdx = Math.max(...list.map((msg, i) => (msg.role === 'user' ? i : -1)));
   165→    const afterLastUser = list.slice(lastUserIdx + 1);
   166→    if (afterLastUser.length === 1 && afterLastUser[0].role === 'assistant') {
   167→      const parts: StreamPart[] = lastStreamedContent.reasoning
   168→        ? [{ type: 'reasoning', content: lastStreamedContent.reasoning }, ...lastStreamedContent.parts]
   169→        : lastStreamedContent.parts;
   170→      list = [...list.slice(0, lastUserIdx + 1), { role: 'assistant', parts: filterParts(parts, hideToolsAndThinking) }];
   171→    }
   172→  }
   173→  return list;
   174→}
   175→
   176→export default function ChatWindow({
   177→  headerTitle,
   178→  conversation,
   179→  providers,
   180→  bots,
   181→  sending,
   182→  streaming,
   183→  lastStreamedContent,
   184→  inputDraft,
   185→  onInputDraftChange,
   186→  onSend,
   187→  onUpdateProvider,
   188→  onUpdateBot,
   189→}: ChatWindowProps) {
   190→  const [hideToolsAndThinking, setHideToolsAndThinking] = useState(false);
   191→  const messagesRef = useRef<HTMLDivElement>(null);
   192→  const topRef = useRef<HTMLDivElement>(null);
   193→  const bottomRef = useRef<HTMLDivElement>(null);
   194→
   195→  const visibleMessages = conversation
   196→    ? getDisplayMessages(conversation.messages, hideToolsAndThinking, lastStreamedContent)
   197→    : [];
   198→
   199→  useEffect(() => {
   200→    bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
   201→  }, [conversation?.messages.length, streaming?.reasoning, streaming?.parts?.length]);
   202→
   203→  const hasProvider = Boolean(conversation?.providerId);
   204→  const isDirectChat = Boolean(
   205→    conversation?.participant1 != null && conversation?.participant2 != null
   206→  );
   207→  const handleSend = () => {
   208→    const trimmed = inputDraft.trim();
   209→    if (!trimmed || sending || !hasProvider) return;
   210→    onSend(trimmed);
   211→  };
   212→
   213→  const scrollToTop = () => topRef.current?.scrollIntoView({ behavior: 'smooth' });
   214→  const scrollToBottom = () => bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
   215→
   216→  if (!conversation) {
   217→    return (
   218→      <main className="flex-1 flex flex-col min-w-0">
   219→        <header className="flex flex-wrap items-center gap-3 py-3.5 px-5 border-b border-border">
   220→          <h2 className="flex-1 min-w-0 text-base font-semibold text-text-bright truncate">{headerTitle}</h2>
   221→        </header>
   222→        <div className="flex-1 flex items-center justify-center text-text-dim text-base">
   223→          <p>
   224→            {headerTitle === 'User'
   225→              ? 'Select or create a conversation to start chatting'
   226→              : `Select or create a conversation with ${headerTitle} to start chatting`}
   227→          </p>
   228→        </div>
   229→      </main>
   230→    );
   231→  }
   232→
   233→  return (
   234→    <main className="flex-1 flex flex-col min-w-0">
   235→      <header className="flex flex-wrap items-center gap-3 py-3.5 px-5 border-b border-border">
   236→        <h2 className="flex-1 min-w-0 text-base font-semibold text-text-bright truncate">{headerTitle}</h2>
   237→        <button
   238→          className={`py-1 px-3 border rounded-lg cursor-pointer text-xs transition-all duration-150 whitespace-nowrap ${
   239→            hideToolsAndThinking
   240→              ? 'bg-bg-active border-accent text-accent'
   241→              : 'bg-bg-input text-text-dim border-border hover:border-accent hover:text-text-bright'
   242→          }`}
   243→          onClick={() => setHideToolsAndThinking((v) => !v)}
   244→          title={hideToolsAndThinking ? 'Show tools and thinking' : 'Hide tools and thinking'}
   245→        >
   246→          {hideToolsAndThinking ? 'Show tools and thinking' : 'Hide tools and thinking'}
   247→        </button>
   248→      </header>
   249→
   250→      <div className="flex-1 overflow-y-auto py-4 px-5 flex flex-col gap-3" ref={messagesRef}>
   251→        <div ref={topRef} />
   252→        {visibleMessages.map((msg, i) => (
   253→          <MessageEntry key={i} msg={msg} conversation={conversation} />
   254→        ))}
   255→        {sending && (() => {
   256→          const assistantLabel = roleDisplayName('assistant', conversation);
   257→          return (
   258→          <div className="max-w-[80%] py-2.5 px-3.5 rounded-lg text-sm leading-relaxed self-start bg-assistant-bg border border-border opacity-95">
   259→            <div className="flex items-baseline gap-2 cursor-pointer select-none">
