@import "tailwindcss";

@theme {
  --color-bg: #1a1b1e;
  --color-bg-sidebar: #141517;
  --color-bg-input: #25262b;
  --color-bg-hover: #2c2e33;
  --color-bg-active: #343a40;
  --color-border: #373a40;
  --color-text: #c1c2c5;
  --color-text-dim: #909296;
  --color-text-bright: #e9ecef;
  --color-accent: #7c5cfc;
  --color-accent-hover: #6741f5;
  --color-user-bg: #2b2d5e;
  --color-assistant-bg: #25262b;
  --color-tool-bg: #1e2a1e;
  --color-tool-border: #2d4a2d;
  --color-tool-text: #8fbc8f;
  --color-tool-summary: #7cb87c;
  --color-danger: #e03131;
  --radius: 8px;
}

@layer base {
  html,
  body,
  #root {
    height: 100%;
    width: 100%;
  }
  body {
    background-color: var(--color-bg);
    color: var(--color-text);
    font-family: 'Inter', system-ui, -apple-system, sans-serif;
    line-height: 1.5;
  }
}

.message-tool-part[open] summary .btn-msg-toggle::after {
  content: '▾';
}
.message-tool-part:not([open]) summary .btn-msg-toggle::after {
  content: '▸';
}

::-webkit-scrollbar {
  width: 6px;
}
::-webkit-scrollbar-track {
  background: transparent;
}
::-webkit-scrollbar-thumb {
  background: var(--color-border);
  border-radius: 3px;
}
::-webkit-scrollbar-thumb:hover {
  background: var(--color-text-dim);
}

.message-tool-part summary::-webkit-details-marker,
.message-tool-part summary::marker {
  display: none;
}

