        const t = event.results[i][0].transcript;
        if (event.results[i].isFinal) {
          finalChunk += t;
        } else {
          interim = t;
        }
      }
      if (finalChunk) {
        pending += (pending ? ' ' : '') + finalChunk.trim();
        const base = inputDraftRef.current.replace(/ *\[…\]$/, '').trimEnd();
        onInputDraftChange(base + (base ? ' ' : '') + pending);
      } else if (interim) {
        const base = inputDraftRef.current.replace(/ *\[…\]$/, '').trimEnd();
        const committed = base.endsWith(pending) ? base.slice(0, base.length - pending.length).trimEnd() : base;
        onInputDraftChange(committed + (committed ? ' ' : '') + (pending ? pending + ' ' : '') + interim + ' […]');
      }
