    82→        var chatModel = chatModelFactory.create(config, loggingTools);
    83→        var promptOptions = chatModelFactory.promptOptions(config, loggingTools);
    84→        if (!(chatModel instanceof StreamingChatModel streamingModel)) {
    85→            var error = "Provider does not support streaming; only streaming models are supported.";
    86→            onComplete.accept(new ChatResult("[Error] " + error, List.of()));
    87→            return Flux.just(new StreamChunk(StreamChunk.TYPE_ANSWER, "[Error] " + error));
    88→        }
    89→
    90→        final StringBuilder contentAccum = new StringBuilder();
    91→        final StringBuilder reasoningAccum = new StringBuilder();
    92→        final var orderedChunks = new ArrayList<StreamChunk>();
    93→        var prompt = promptOptions != null ? new Prompt(contextMessages, promptOptions) : new Prompt(contextMessages);
    94→
    95→        var contentStream = streamingModel.stream(prompt)
    96→                .flatMap(response -> {
    97→                    var c = toStreamChunk(response);
    98→                    return c != null ? Flux.just(c) : Flux.empty();
    99→                })
   100→                .doOnNext(c -> {
   101→                    if (StreamChunk.TYPE_REASONING.equals(c.type())) {
   102→                        reasoningAccum.append(c.content());
   103→                    } else if (StreamChunk.TYPE_ANSWER.equals(c.type())) {
   104→                        contentAccum.append(c.content());
   105→                    }
   106→                })
   107→                .doOnComplete(() -> sink.emitComplete(Sinks.EmitFailureHandler.FAIL_FAST))
   108→                .doOnError(e -> sink.emitComplete(Sinks.EmitFailureHandler.FAIL_FAST));
   109→
   110→        var merged = Flux.merge(contentStream, sink.asFlux())
   111→                .doOnNext(c -> {
   112→                    if (StreamChunk.TYPE_ANSWER.equals(c.type()) || StreamChunk.TYPE_TOOL.equals(c.type())) {
   113→                        orderedChunks.add(c);
   114→                    }
   115→                });
   116→        return merged
   117→                .doOnComplete(() -> {
   118→                    var pendingIds = delegationTools != null
   119→                            ? delegationTools.getPendingSubConversationIds() : List.<String>of();
   120→                    var parts = coalesceOrderedChunks(orderedChunks);
   121→                    var reasoning = reasoningAccum.isEmpty() ? null : reasoningAccum.toString();
   122→                    var partsWithReasoning = new ArrayList<StreamChunk>();
   123→                    if (reasoning != null && !reasoning.isEmpty()) {
   124→                        partsWithReasoning.add(new StreamChunk(StreamChunk.TYPE_REASONING, reasoning));
   125→                    }
   126→                    partsWithReasoning.addAll(parts);
   127→                    onComplete.accept(new ChatResult(contentAccum.toString(), pendingIds,
   128→                            partsWithReasoning.isEmpty() ? null : partsWithReasoning, reasoning));
   129→                })
   130→                .doOnError(e -> onComplete.accept(new ChatResult("[Error] " + e.getMessage(), List.of())));
   131→    }
   132→
   133→    private static List<StreamChunk> coalesceOrderedChunks(List<StreamChunk> orderedChunks) {
   134→        if (orderedChunks.isEmpty()) {
   135→            return List.of();
   136→        }
   137→        var parts = new ArrayList<StreamChunk>();
   138→        var answerAccum = new StringBuilder();
   139→        for (var c : orderedChunks) {
   140→            if (StreamChunk.TYPE_ANSWER.equals(c.type())) {
   141→                answerAccum.append(c.content());
   142→            } else {
   143→                if (answerAccum.length() > 0) {
   144→                    parts.add(new StreamChunk(StreamChunk.TYPE_ANSWER, answerAccum.toString()));
   145→                    answerAccum.setLength(0);
   146→                }
   147→                parts.add(c);
   148→            }
   149→        }
   150→        if (answerAccum.length() > 0) {
   151→            parts.add(new StreamChunk(StreamChunk.TYPE_ANSWER, answerAccum.toString()));
   152→        }
   153→        return parts;
   154→    }
   155→
   156→    private StreamChunk toStreamChunk(ChatResponse response) {
   157→        var result = response.getResult();
   158→        if (result == null) {
   159→            return null;
   160→        }
   161→        var output = result.getOutput();
   162→        if (output == null) {
   163→            return null;
   164→        }
   165→        var metadata = output.getMetadata();
   166→        if (metadata != null) {
   167→            for (var key : REASONING_KEYS) {
   168→                var value = metadata.get(key);
   169→                if (value != null && !value.toString().isEmpty()) {
   170→                    return new StreamChunk(StreamChunk.TYPE_REASONING, value.toString());
   171→                }
   172→            }
   173→            if (metadata.containsKey("signature")) {
   174→                var text = output.getText();
   175→                if (text != null && !text.isEmpty()) {
   176→                    return new StreamChunk(StreamChunk.TYPE_REASONING, text);
   177→                }
   178→            }
   179→        }
   180→        var text = output.getText();
   181→        return new StreamChunk(StreamChunk.TYPE_ANSWER, text != null ? text : "");
   182→    }
   183→}
