   109→    public String sendMessage(String conversationId, String userMessage) {
   110→        var conversation = conversationRepository.findById(conversationId)
   111→                .orElseThrow(() -> new IllegalArgumentException("Conversation not found: " + conversationId));
   112→        if (conversation.providerId() == null || conversation.providerId().isBlank()) {
   113→            throw new IllegalArgumentException("No agent selected for this conversation");
   114→        }
   115→        conversation.messages().add(ChatMessage.of("user", userMessage));
   116→        var bot = botService.getBot(conversation.botName());
   117→        var senderIdentity = senderIdentity(conversation);
   118→        var result = bot.chat(conversation.providerId(), conversation.messages(), conversationId, senderIdentity);
   119→        conversation.messages().add(ChatMessage.of("assistant", result.assistantContent()));
   120→        conversationRepository.save(conversation);
   121→
   122→        if (!result.pendingSubConversationIds().isEmpty()) {
   123→            var delegationService = delegationServiceProvider.getIfAvailable();
   124→            if (delegationService != null) {
   125→                delegationService.startSubAgents(result.pendingSubConversationIds());
   126→            }
   127→        }
   128→
   129→        return result.response();
   130→    }
