   132→    public Flux<StreamChunk> sendMessageStream(String conversationId, String userMessage) {
   133→        var conversation = conversationRepository.findById(conversationId)
   134→                .orElseThrow(() -> new IllegalArgumentException("Conversation not found: " + conversationId));
   135→        if (conversation.providerId() == null || conversation.providerId().isBlank()) {
   136→            return Flux.error(new IllegalArgumentException("No agent selected for this conversation"));
   137→        }
   138→        conversation.messages().add(ChatMessage.of("user", userMessage));
   139→        conversationRepository.save(conversation);
   140→
   141→        var bot = botService.getBot(conversation.botName());
   142→        var senderIdentity = senderIdentity(conversation);
   143→        return bot.chatStream(conversation.providerId(), conversation.messages(), conversationId, result -> {
   144→            conversation.messages().add(ChatMessage.of("assistant", result.assistantContent()));
   145→            conversationRepository.save(conversation);
   146→            if (!result.pendingSubConversationIds().isEmpty()) {
   147→                var delegationService = delegationServiceProvider.getIfAvailable();
   148→                if (delegationService != null) {
   149→                    delegationService.startSubAgents(result.pendingSubConversationIds());
   150→                }
   151→            }
   152→        }, senderIdentity);
   153→    }
