   155→    private static String senderIdentity(Conversation conversation) {
   156→        if (!conversation.isDirect() || conversation.botName() == null) return null;
   157→        var p1 = conversation.participant1();
   158→        var p2 = conversation.participant2();
   159→        if (p1 == null || p2 == null) return null;
   160→        var other = p1.equals(conversation.botName()) ? p2 : p1;
   161→        return "user".equalsIgnoreCase(other) ? null : other;
   162→    }
