     7→
     8→import java.util.List;
     9→import java.util.function.Consumer;
    10→
    11→public class LoggingToolCallback implements ToolCallback {
    12→
    13→    private final ToolCallback delegate;
    14→    private final List<ChatMessage> toolLog;
    15→    private final String serverName;
    16→    private final Consumer<StreamChunk> onToolChunk;
    17→
    18→    public LoggingToolCallback(ToolCallback delegate, List<ChatMessage> toolLog) {
    19→        this(delegate, toolLog, null, null);
    20→    }
    21→
    22→    public LoggingToolCallback(ToolCallback delegate, List<ChatMessage> toolLog, String serverName) {
    23→        this(delegate, toolLog, serverName, null);
    24→    }
    25→
    26→    public LoggingToolCallback(ToolCallback delegate, List<ChatMessage> toolLog, String serverName,
    27→                               Consumer<StreamChunk> onToolChunk) {
    28→        this.delegate = delegate;
    29→        this.toolLog = toolLog;
    30→        this.serverName = serverName;
    31→        this.onToolChunk = onToolChunk;
    32→    }
    33→
    34→    @Override
    35→    public ToolDefinition getToolDefinition() {
    36→        var def = delegate.getToolDefinition();
    37→        if (serverName == null || serverName.isBlank()) {
    38→            return def;
    39→        }
    40→        var prefixed = serverName + "." + def.name();
    41→        return ToolDefinition.builder()
    42→                .name(sanitizeToolName(prefixed))
    43→                .description(def.description())
    44→                .inputSchema(def.inputSchema())
    45→                .build();
    46→    }
    47→
    48→    private static String sanitizeToolName(String name) {
    49→        return name.replaceAll("[^a-zA-Z0-9_-]", "_");
    50→    }
    51→
    52→    @Override
    53→    public ToolMetadata getToolMetadata() {
    54→        return delegate.getToolMetadata();
    55→    }
    56→
    57→    @Override
    58→    public String call(String toolInput) {
    59→        var result = delegate.call(toolInput);
    60→        log(toolInput, result);
    61→        return result;
    62→    }
    63→
    64→    @Override
    65→    public String call(String toolInput, ToolContext toolContext) {
    66→        var result = delegate.call(toolInput, toolContext);
    67→        log(toolInput, result);
    68→        return result;
    69→    }
    70→
    71→    private void log(String input, String output) {
    72→        var toolName = delegate.getToolDefinition().name();
    73→        var label = serverName != null ? serverName + " > " + toolName : toolName;
    74→        var content = "[" + label + "]\nInput: " + input + "\nOutput: " + output;
    75→        toolLog.add(ChatMessage.of("tool", content));
    76→        if (onToolChunk != null) {
    77→            onToolChunk.accept(new StreamChunk(StreamChunk.TYPE_TOOL, content));
    78→        }
    79→    }
    80→}
