    52→    public List<ToolCallback> buildToolCallbacks(StreamRequestMetadata meta, String providerId) {
    53→        var filtered = meta.messages().stream().filter(m -> !"tool".equals(m.role())).toList();
    54→        var list = new ArrayList<ToolCallback>();
    55→
    56→        list.addAll(Arrays.asList(ToolCallbacks.from(new ChatTools(skillsService, jobExecutor, providerId, filtered,
    57→                meta.conversationLimit(), meta.botName(), botRepository))));
    58→        list.addAll(Arrays.asList(ToolCallbacks.from(new ShellTool(shellAccessService))));
    59→
    60→        var botName = meta.botName();
    61→        if (botName != null && !botName.isBlank() && !"default".equalsIgnoreCase(botName)) {
    62→            list.addAll(Arrays.asList(ToolCallbacks.from(new BotToBotTool(conversationService, botRepository, providerId, botName))));
    63→        }
