   182→function parseStructuredContent(content: string): StreamPart[] | null {
   183→  if (!content || typeof content !== 'string') return null;
   184→  const trimmed = content.trim();
   185→  if (!trimmed.startsWith('{"parts":')) return null;
   186→  try {
   187→    const data = JSON.parse(content) as { parts?: Array<{ type: string; content: string }> };
   188→    if (!Array.isArray(data.parts)) return null;
   189→    const parts: StreamPart[] = data.parts
   190→      .filter((p) => p && (p.type === 'answer' || p.type === 'tool' || p.type === 'reasoning') && typeof p.content === 'string')
   191→      .map((p) => ({ type: p.type as 'answer' | 'tool' | 'reasoning', content: p.content }));
   192→    return parts.length > 0 ? parts : null;
   193→  } catch {
   194→    return null;
   195→  }
   196→}
   197→
   198→function filterParts(parts: StreamPart[], hideToolsAndThinking: boolean): StreamPart[] {
   199→  if (!hideToolsAndThinking) return parts;
   200→  const answerParts = parts.filter((p) => p.type === 'answer');
   201→  return answerParts.map((p, i, arr) => ({
   202→    ...p,
   203→    content: p.content + (i < arr.length - 1 ? '\n\n' : ''),
   204→  }));
   205→}
   206→
   207→function getDisplayMessages(
   208→  messages: ChatMessage[],
   209→  hideToolsAndThinking: boolean,
   210→  lastStreamedContent: { reasoning: string; parts: StreamPart[] } | null
   211→): DisplayMessage[] {
   212→  let list: DisplayMessage[] = messages.map((msg) => {
   213→    if (msg.role === 'assistant') {
   214→      const parts = parseStructuredContent(msg.content);
   215→      if (parts) return { role: 'assistant' as const, parts: filterParts(parts, hideToolsAndThinking) };
   216→    }
   217→    return msg;
   218→  });
   219→  if (lastStreamedContent && list.length > 0) {
   220→    const lastUserIdx = Math.max(...list.map((msg, i) => (msg.role === 'user' ? i : -1)));
   221→    const afterLastUser = list.slice(lastUserIdx + 1);
   222→    if (afterLastUser.length === 1 && afterLastUser[0].role === 'assistant') {
   223→      const parts: StreamPart[] = lastStreamedContent.reasoning
   224→        ? [{ type: 'reasoning', content: lastStreamedContent.reasoning }, ...lastStreamedContent.parts]
   225→        : lastStreamedContent.parts;
   226→      list = [...list.slice(0, lastUserIdx + 1), { role: 'assistant', parts: filterParts(parts, hideToolsAndThinking) }];
   227→    }
   228→  }
   229→  return list;
   230→}
