    25→  const [lastStreamedContent, setLastStreamedContent] = useState<{ conversationId: string; reasoning: string; parts: StreamPart[] } | null>(null);
    26→  const [, setDraftVersion] = useState(0);
    27→  const inputDraftRef = useRef('');
    28→  const streamingRef = useRef<StreamingContent | null>(null);
    29→  const pollIntervalRef = useRef<ReturnType<typeof setInterval> | null>(null);
    30→  const activeIdRef = useRef(activeId);
    31→  const selectedBotRef = useRef(selectedBot);
    32→  activeIdRef.current = activeId;
    33→  selectedBotRef.current = selectedBot;
    34→
    35→  const setInputDraft = (value: string) => {
    36→    inputDraftRef.current = value;
    37→    setDraftVersion((v) => v + 1);
    38→  };
    39→
    40→  useEffect(() => {
    41→    api.fetchProviders().then(setProviders);
    42→    api.fetchBots().then(setBots);
    43→  }, []);
    44→
    45→  useEffect(() => {
    46→    const participant = selectedBot ?? 'user';
    47→    api.fetchConversations(participant).then(setConversations);
    48→  }, [selectedBot]);
    49→
    50→  useEffect(() => {
    51→    return () => {
    52→      if (pollIntervalRef.current) clearInterval(pollIntervalRef.current);
    53→    };
    54→  }, []);
    55→
    56→  const activeConversation = conversations.find((c) => c.id === activeId) ?? null;
    57→  const displayConversations =
    58→    selectedBot != null
    59→      ? conversations
    60→      : conversations.filter((c) => !(c.participant1 != null && c.participant2 != null));
    61→  const headerTitle = selectedBot ?? 'User';
    62→
    63→  useEffect(() => {
    64→    if (activeId != null && !displayConversations.some((c) => c.id === activeId)) {
    65→      setActiveId(null);
    66→    }
    67→  }, [selectedBot, activeId, displayConversations]);
    68→
    69→  const handleAddProvider = async (req: CreateProviderRequest) => {
    70→    const created = await api.createProvider(req);
    71→    setProviders((prev) => [...prev, created]);
    72→  };
    73→
    74→  const handleAddBot = async (req: CreateBotRequest) => {
    75→    const created = await api.createBot(req);
    76→    setBots((prev) => [...prev, created]);
    77→  };
    78→
    79→  const handleCreateConversation = async (name: string, providerId?: string | null) => {
    80→    const res = await api.createConversation(name, providerId);
    81→    const conv: Conversation = {
    82→      id: res.conversationId,
    83→      name: res.name,
    84→      providerId: res.providerId ?? null,
    85→      botName: res.botName ?? null,
    86→      messages: [],
    87→    };
    88→    setConversations((prev) => [...prev, conv]);
    89→    setActiveId(conv.id);
    90→  };
    91→
    92→  const handleOpenDirectChat = async (botName: string, providerId?: string | null) => {
    93→    const conv = await api.getOrCreateDirectConversation(botName, providerId);
    94→    setConversations((prev) => {
    95→      const exists = prev.some((c) => c.id === conv.id);
    96→      if (exists) return prev.map((c) => (c.id === conv.id ? conv : c));
    97→      return [...prev, conv];
    98→    });
    99→    setActiveId(conv.id);
   100→  };
   101→
   102→  const handleNewConversationWithBot = async (botName: string) => {
   103→    setSelectedBot(botName);
   104→    await handleOpenDirectChat(botName);
   105→  };
   106→
   107→  const handleUpdateConversationProvider = async (id: string, providerId: string | null) => {
   108→    const updated = await api.updateConversation(id, { providerId });
   109→    setConversations((prev) =>
   110→      prev.map((c) => (c.id === id ? { ...c, providerId: updated.providerId ?? null } : c)),
   111→    );
   112→  };
   113→
   114→  const handleUpdateConversationBot = async (id: string, botName: string | null) => {
   115→    const updated = await api.updateConversation(id, { botName });
   116→    setConversations((prev) =>
   117→      prev.map((c) => (c.id === id ? { ...c, botName: updated.botName ?? null } : c)),
   118→    );
   119→  };
   120→
   121→  const handleDeleteConversation = async (id: string) => {
   122→    await api.deleteConversation(id);
   123→    setConversations((prev) => prev.filter((c) => c.id !== id));
   124→    if (activeId === id) setActiveId(null);
   125→  };
   126→
   127→  const handleSend = async (message: string) => {
   128→    if (!activeId) return;
   129→    inputDraftRef.current = '';
   130→    setDraftVersion((v) => v + 1);
   131→    if (pollIntervalRef.current) {
   132→      clearInterval(pollIntervalRef.current);
   133→      pollIntervalRef.current = null;
   134→    }
   135→    setLastStreamedContent(null);
   136→    setConversations((prev) =>
   137→      prev.map((c) =>
   138→        c.id === activeId
   139→          ? { ...c, messages: [...c.messages, { role: 'user', content: message, timestampMillis: Date.now() }] }
   140→          : c,
   141→      ),
   142→    );
   143→    setSending(true);
   144→    const initial: StreamingContent = { reasoning: '', parts: [] };
   145→    setStreaming(initial);
   146→    streamingRef.current = initial;
   147→    api.sendMessageStream(
   148→      activeId,
   149→      message,
   150→      (chunk) => {
   151→        setStreaming((prev) => {
   152→          if (!prev) return prev;
   153→          let next: StreamingContent;
   154→          if (chunk.type === 'reasoning') {
   155→            next = { ...prev, reasoning: prev.reasoning + chunk.content };
   156→          } else if (chunk.type === 'tool') {
   157→            next = { ...prev, parts: [...prev.parts, { type: 'tool', content: chunk.content }] };
   158→          } else {
   159→            const prevParts = prev.parts;
   160→            const last = prevParts[prevParts.length - 1];
   161→            if (last?.type === 'answer') {
   162→              next = {
   163→                ...prev,
   164→                parts: [...prevParts.slice(0, -1), { type: 'answer', content: last.content + chunk.content }],
   165→              };
   166→            } else {
   167→              next = { ...prev, parts: [...prevParts, { type: 'answer', content: chunk.content }] };
   168→            }
   169→          }
   170→          streamingRef.current = next;
   171→          return next;
   172→        });
   173→      },
   174→      () => {
   175→        const ref = streamingRef.current;
   176→        if (activeId && ref && (ref.reasoning || ref.parts.length > 0)) {
   177→          setLastStreamedContent({ conversationId: activeId, reasoning: ref.reasoning ?? '', parts: ref.parts });
   178→        }
   179→        setSending(false);
   180→        setStreaming(null);
   181→        streamingRef.current = null;
   182→        const participant = selectedBotRef.current ?? 'user';
   183→        const poll = () => {
   184→          api.fetchConversations(participant).then((list) => setConversations([...list]));
   185→        };
   186→        poll();
   187→        pollIntervalRef.current = setInterval(poll, 2500);
   188→        setTimeout(() => {
   189→          if (pollIntervalRef.current) {
   190→            clearInterval(pollIntervalRef.current);
   191→            pollIntervalRef.current = null;
   192→          }
   193→        }, 60000);
   194→      },
   195→      () => {
   196→        setSending(false);
   197→        setStreaming(null);
   198→        streamingRef.current = null;
   199→        api.fetchConversations(selectedBotRef.current ?? 'user').then(setConversations);
   200→      }
   201→    );
   202→  };
   203→
   204→  return (
   205→    <div className="flex h-screen">
   206→      <Sidebar
   207→        providers={providers}
   208→        bots={bots}
   209→        conversations={displayConversations}
   210→        activeId={activeId}
   211→        selectedBot={selectedBot}
   212→        onSelectBot={setSelectedBot}
   213→        onSelectConversation={setActiveId}
   214→        onCreateConversation={handleCreateConversation}
   215→        onNewConversationWithBot={handleNewConversationWithBot}
   216→        onDeleteConversation={handleDeleteConversation}
   217→        onAddProvider={handleAddProvider}
   218→        onAddBot={handleAddBot}
   219→      />
   220→      <ChatWindow
   221→        key={activeId ?? ''}
   222→        headerTitle={headerTitle}
   223→        conversation={activeConversation}
   224→        providers={providers}
   225→        bots={bots}
   226→        sending={sending}
   227→        streaming={streaming}
   228→        lastStreamedContent={activeId && lastStreamedContent?.conversationId === activeId ? lastStreamedContent : null}
   229→        inputDraft={inputDraftRef.current}
   230→        onInputDraftChange={setInputDraft}
   231→        onSend={handleSend}
   232→        onUpdateProvider={handleUpdateConversationProvider}
   233→        onUpdateBot={handleUpdateConversationBot}
   234→      />
   235→    </div>
   236→  );
   237→}
