    31→    public String messageBot(
    32→            @ToolParam(description = "Name of the bot to message (e.g. trickster, maverick)") String targetBotName,
    33→            @ToolParam(description = "The message or question to send to the other bot") String message) {
    34→        if (currentBotName == null || currentBotName.isBlank() || "default".equalsIgnoreCase(currentBotName)) {
