     1→import type { Bot, Conversation, CreateBotRequest, CreateProviderRequest, Provider } from './types';
     2→
     3→const JSON_HEADERS = { 'Content-Type': 'application/json' };
     4→
     5→export async function fetchProviders(): Promise<Provider[]> {
     6→  const res = await fetch('/api/providers');
     7→  return res.json();
     8→}
     9→
    10→export async function createProvider(req: CreateProviderRequest): Promise<Provider> {
    11→  const res = await fetch('/api/providers', {
    12→    method: 'POST',
    13→    headers: JSON_HEADERS,
    14→    body: JSON.stringify(req),
    15→  });
    16→  return res.json();
    17→}
    18→
    19→export async function deleteProvider(id: string): Promise<void> {
    20→  await fetch(`/api/providers/${id}`, { method: 'DELETE' });
    21→}
    22→
    23→export async function fetchConversations(participant?: string | null): Promise<Conversation[]> {
    24→  const url = participant != null && participant !== ''
    25→    ? `/api/conversations?participant=${encodeURIComponent(participant)}`
    26→    : '/api/conversations';
    27→  const res = await fetch(url);
    28→  return res.json();
    29→}
    30→
    31→export async function getOrCreateDirectConversation(
    32→  botName: string,
    33→  providerId?: string | null
    34→): Promise<Conversation> {
    35→  const params = providerId ? `?providerId=${encodeURIComponent(providerId)}` : '';
    36→  const res = await fetch(`/api/conversations/direct/${encodeURIComponent(botName)}${params}`);
    37→  if (!res.ok) {
    38→    const err = await res.text();
    39→    throw new Error(err || res.statusText);
    40→  }
    41→  return res.json();
    42→}
    43→
    44→export async function createConversation(
    45→  name: string,
    46→  providerId?: string | null
    47→): Promise<{ conversationId: string; name: string; providerId: string | null; botName?: string | null }> {
    48→  const res = await fetch('/api/conversations', {
    49→    method: 'POST',
    50→    headers: JSON_HEADERS,
    51→    body: JSON.stringify(providerId != null ? { name, providerId } : { name }),
    52→  });
    53→  return res.json();
    54→}
    55→
    56→export async function updateConversation(
    57→  id: string,
    58→  patch: { providerId?: string | null; botName?: string | null }
    59→): Promise<Conversation> {
    60→  const res = await fetch(`/api/conversations/${id}`, {
    61→    method: 'PATCH',
    62→    headers: JSON_HEADERS,
    63→    body: JSON.stringify(patch),
    64→  });
    65→  return res.json();
    66→}
    67→
    68→export interface StreamChunk {
    69→  type: 'reasoning' | 'answer' | 'tool';
    70→  content: string;
    71→}
    72→
    73→export async function sendMessage(conversationId: string, message: string): Promise<string> {
    74→  const res = await fetch(`/api/conversations/${conversationId}/messages`, {
    75→    method: 'POST',
    76→    headers: JSON_HEADERS,
    77→    body: JSON.stringify({ message }),
    78→  });
    79→  const data = await res.json();
    80→  return data.response;
    81→}
    82→
    83→export function sendMessageStream(
    84→  conversationId: string,
    85→  message: string,
    86→  onChunk: (chunk: StreamChunk) => void,
    87→  onDone: () => void,
    88→  onError: (err: unknown) => void
    89→): void {
    90→  fetch(`/api/conversations/${conversationId}/messages/stream`, {
    91→    method: 'POST',
    92→    headers: JSON_HEADERS,
    93→    body: JSON.stringify({ message }),
    94→  })
    95→    .then(async (res) => {
    96→      if (!res.ok || !res.body) {
    97→        onError(new Error(res.statusText));
    98→        return;
    99→      }
   100→      const reader = res.body.getReader();
   101→      const decoder = new TextDecoder();
   102→      let buffer = '';
   103→      while (true) {
   104→        const { done, value } = await reader.read();
   105→        if (done) break;
   106→        buffer += decoder.decode(value, { stream: true });
   107→        const events = buffer.split('\n\n');
   108→        buffer = events.pop() ?? '';
   109→        for (const event of events) {
   110→          const dataLine = event.split('\n').find((l) => l.startsWith('data:'));
   111→          if (dataLine) {
   112→            const data = dataLine.slice(5).trim();
   113→            if (data) {
   114→              try {
   115→                onChunk(JSON.parse(data) as StreamChunk);
   116→              } catch {
   117→                // skip non-JSON
   118→              }
   119→            }
   120→          }
   121→        }
   122→      }
   123→      if (buffer.trim()) {
   124→        const dataLine = buffer.split('\n').find((l) => l.startsWith('data:'));
   125→        if (dataLine) {
   126→          const data = dataLine.slice(5).trim();
   127→          if (data) {
   128→            try {
   129→              onChunk(JSON.parse(data) as StreamChunk);
   130→            } catch {
   131→              // skip
   132→            }
   133→          }
