    16→import org.springframework.stereotype.Service;
    17→import reactor.core.publisher.Flux;
    18→import reactor.core.publisher.Sinks;
    19→
    20→import java.util.ArrayList;
    21→import java.util.List;
    22→import java.util.concurrent.atomic.AtomicReference;
    23→import java.util.function.Consumer;
    24→
    25→@Service
    26→public class ChatService {
    27→
    28→    private static final List<String> REASONING_KEYS =
    29→            List.of("thinking", "reasoningContent", "reasoning_content", "reasoning");
    30→
    31→    private final ProviderConfigRepository configRepository;
    32→    private final ChatModelFactory chatModelFactory;
    33→    private final ChatToolCallbacksService toolCallbacksService;
    34→    private final McpService mcpService;
    35→    private final ConversationRepository conversationRepository;
    36→    private final boolean delegationEnabled;
    37→
    38→    public ChatService(ProviderConfigRepository configRepository,
    39→                       ChatModelFactory chatModelFactory,
    40→                       ChatToolCallbacksService toolCallbacksService,
    41→                       McpService mcpService,
    42→                       ConversationRepository conversationRepository,
    43→                       @Value("${aidaemon.delegation-enabled:false}") boolean delegationEnabled) {
    44→        this.configRepository = configRepository;
    45→        this.chatModelFactory = chatModelFactory;
    46→        this.toolCallbacksService = toolCallbacksService;
    47→        this.mcpService = mcpService;
    48→        this.conversationRepository = conversationRepository;
    49→        this.delegationEnabled = delegationEnabled;
    50→    }
    51→
    52→    public ChatResult streamAndCollect(String providerId, List<Message> contextMessages, StreamRequestMetadata meta) {
    53→        var resultRef = new AtomicReference<ChatResult>();
    54→        stream(providerId, contextMessages, meta, resultRef::set).blockLast();
    55→        return resultRef.get();
    56→    }
    57→
    58→    public Flux<StreamChunk> stream(String providerId, List<Message> contextMessages, StreamRequestMetadata meta,
    59→                                   Consumer<ChatResult> onComplete) {
    60→        var config = configRepository.findById(providerId)
    61→                .orElseThrow(() -> new IllegalArgumentException("Provider not found: " + providerId));
    62→
    63→        final var toolLog = new ArrayList<ChatMessage>();
    64→        var sink = Sinks.many().unicast().<StreamChunk>onBackpressureBuffer();
    65→        var onToolChunk = (Consumer<StreamChunk>) c -> sink.tryEmitNext(c);
    66→        var loggingTools = new ArrayList<ToolCallback>();
    67→        for (var t : toolCallbacksService.buildToolCallbacks(meta, config.id())) {
    68→            loggingTools.add(new LoggingToolCallback(t, toolLog, null, onToolChunk));
    69→        }
    70→        mcpService.getToolCallbacksByServer().forEach((serverName, callbacks) ->
    71→                callbacks.forEach(t -> loggingTools.add(new LoggingToolCallback(t, toolLog, serverName, onToolChunk))));
    72→
    73→        final DelegationTools delegationTools = (delegationEnabled && meta.conversationId() != null)
    74→                ? new DelegationTools(conversationRepository, meta.conversationId(), providerId, meta.botName())
    75→                : null;
    76→        if (delegationTools != null) {
    77→            for (var t : org.springframework.ai.support.ToolCallbacks.from(delegationTools)) {
    78→                loggingTools.add(new LoggingToolCallback(t, toolLog, null, onToolChunk));
    79→            }
    80→        }
    81→
    82→        var chatModel = chatModelFactory.create(config, loggingTools);
    83→        var promptOptions = chatModelFactory.promptOptions(config, loggingTools);
    84→        if (!(chatModel instanceof StreamingChatModel streamingModel)) {
