     1→import { useEffect, useRef, useState } from 'react';
     2→import Sidebar from './components/Sidebar';
     3→import ChatWindow from './components/ChatWindow';
     4→import * as api from './api';
     5→import type { Bot, Conversation, CreateBotRequest, CreateProviderRequest, Provider } from './types';
     6→
     7→export interface StreamPart {
     8→  type: 'answer' | 'tool' | 'reasoning';
     9→  content: string;
    10→}
    11→
    12→export interface StreamingContent {
    13→  reasoning: string;
    14→  parts: StreamPart[];
    15→}
    16→
    17→export default function App() {
    18→  const [providers, setProviders] = useState<Provider[]>([]);
    19→  const [bots, setBots] = useState<Bot[]>([]);
    20→  const [conversations, setConversations] = useState<Conversation[]>([]);
    21→  const [activeId, setActiveId] = useState<string | null>(null);
    22→  const [selectedBot, setSelectedBot] = useState<string | null>(null);
    23→  const [sending, setSending] = useState(false);
    24→  const [streaming, setStreaming] = useState<StreamingContent | null>(null);
    25→  const [lastStreamedContent, setLastStreamedContent] = useState<{ conversationId: string; reasoning: string; parts: StreamPart[] } | null>(null);
    26→  const [, setDraftVersion] = useState(0);
    27→  const inputDraftRef = useRef('');
    28→  const streamingRef = useRef<StreamingContent | null>(null);
    29→  const pollIntervalRef = useRef<ReturnType<typeof setInterval> | null>(null);
    30→  const activeIdRef = useRef(activeId);
    31→  const selectedBotRef = useRef(selectedBot);
    32→  activeIdRef.current = activeId;
    33→  selectedBotRef.current = selectedBot;
    34→
    35→  const setInputDraft = (value: string) => {
    36→    inputDraftRef.current = value;
    37→    setDraftVersion((v) => v + 1);
    38→  };
    39→
    40→  useEffect(() => {
    41→    api.fetchProviders().then(setProviders);
    42→    api.fetchBots().then(setBots);
    43→  }, []);
    44→
    45→  useEffect(() => {
    46→    const participant = selectedBot ?? 'user';
    47→    api.fetchConversations(participant).then(setConversations);
    48→  }, [selectedBot]);
    49→
    50→  useEffect(() => {
    51→    return () => {
    52→      if (pollIntervalRef.current) clearInterval(pollIntervalRef.current);
    53→    };
